let _cache: Uint8Array | null = null;

function getLookup(): Uint8Array {
  if (!_cache) {
    _cache = new Uint8Array(Buffer.from(LOOKUP_B64, "base64"));
  }
  return _cache;
}

function isLeap(y: number): boolean {
  return (y % 4 === 0 && y % 100 !== 0) || y % 400 === 0;
}

function daysSince1920(y: number, m: number, d: number): number {
  let days = 0;
  for (let yr = LOOKUP_START_YEAR; yr < y; yr++) {
    days += isLeap(yr) ? 366 : 365;
  }
  const dm = [31, isLeap(y) ? 29 : 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
  for (let i = 0; i < m - 1; i++) days += dm[i];
  return days + d - 1;
}

/**
 * 生年月日から宿(ms)を取得 (1-27)
 * syukuyo.com と100%一致する精密ルックアップ
 * 範囲外の日付は天文学的近似で算出
 */
export function getSukuyouMs(year: number, month: number, day: number): number {
  if (year >= LOOKUP_START_YEAR && year <= 2025) {
    const idx = daysSince1920(year, month, day);
    const lookup = getLookup();
    if (idx >= 0 && idx < lookup.length) {
      return lookup[idx];
    }
  }
  return astronomicalFallback(year, month, day);
}

function astronomicalFallback(y: number, m: number, d: number): number {
  // Reference: 2000-01-01 = ms 16 (心宿)
  // Moon sidereal period ≈ 27.321661 days
  const refJD = 2451545.125;
  let yy = y, mm = m;
  if (mm <= 2) { yy--; mm += 12; }
  const A = Math.floor(yy / 100);
  const B = 2 - A + Math.floor(A / 4);
  const jd = Math.floor(365.25 * (yy + 4716)) + Math.floor(30.6001 * (mm + 1)) + d + B - 1524.5 + 15.0 / 24.0;
  const diff = jd - refJD;
  const cycle = diff / 27.321661;
  const phase = ((cycle % 1) + 1) % 1;
  return ((Math.floor(phase * 27) + 15) % 27) + 1;
}

export const SHUKU_NAMES = [
  "昴宿", "畢宿", "觜宿", "参宿", "井宿", "鬼宿", "柳宿", "星宿", "張宿",
  "翼宿", "軫宿", "角宿", "亢宿", "氐宿", "房宿", "心宿", "尾宿", "箕宿",
  "斗宿", "女宿", "虚宿", "危宿", "室宿", "壁宿", "奎宿", "婁宿", "胃宿"
] as const;

export function getShukuName(ms: number): string {
  return SHUKU_NAMES[(ms - 1) % 27];
}
